<span class="line"><span style="color:#BABED8;">        </span><span style="color:#FFCB6B;">loopback</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">loop</span><span style="color:#BABED8;"> $isofile</span></span>
