<span class="line"><span style="color:#BABED8;">        </span><span style="color:#FFCB6B;">initrd</span><span style="color:#BABED8;"> (loop)/arch/boot/intel-ucode.img </span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">loop</span><span style="color:#89DDFF;">)</span><span style="color:#BABED8;">/arch/boot/amd-ucode.img </span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">loop</span><span style="color:#89DDFF;">)</span><span style="color:#BABED8;">/arch/boot/x86_64/initramfs-linux.img</span></span>
